use std::collections::HashMap;

fn solve(points: Vec<Vec<i64>>) -> i64 {
    fn gcd(a: u64, b: u64) -> u64 {
        if b == 0 {
            a
        } else {
            gcd(b, a % b)
        }
    }

    let n = points.len();
    let mut slope_map: HashMap<(i64, i64), HashMap<i64, i64>> = HashMap::new();

    for i in 0..n {
        for j in (i + 1)..n {
            let xi = points[i][0];
            let yi = points[i][1];
            let xj = points[j][0];
            let yj = points[j][1];
            let dx = xj - xi;
            let dy = yj - yi;

            if dx == 0 && dy == 0 {
                continue;
            }
            let (key_slope, intercept) = if dx == 0 {
                ((0, 1), xi)
            } else if dy == 0 {
                ((1, 0), -yi)
            } else {
                let dx_abs = dx.abs() as u64;
                let dy_abs = dy.abs() as u64;
                let g_val = gcd(dx_abs, dy_abs) as i64;
                let mut dx_norm = dx / g_val;
                let mut dy_norm = dy / g_val;
                if dx_norm < 0 || (dx_norm == 0 && dy_norm < 0) {
                    dx_norm = -dx_norm;
                    dy_norm = -dy_norm;
                }
                let c = dy_norm * xi - dx_norm * yi;
                ((dx_norm, dy_norm), c)
            };
            *slope_map.entry(key_slope).or_insert(HashMap::new()).entry(intercept).or_insert(0) += 1;
        }
    }

    let mut T = 0i64;
    for inner_map in slope_map.values() {
        let total_segments: i64 = inner_map.values().sum();
        let sq_sum: i64 = inner_map.values().map(|&count| count * count).sum();
        let pairs = (total_segments * total_segments - sq_sum) / 2;
        T += pairs;
    }

    let mut mid_k: HashMap<(i64, i64), i64> = HashMap::new();
    let mut mid_deg: HashMap<(i64, i64), HashMap<usize, i64>> = HashMap::new();
    for i in 0..n {
        for j in (i + 1)..n {
            let xi = points[i][0];
            let yi = points[i][1];
            let xj = points[j][0];
            let yj = points[j][1];
            let mid = (xi + xj, yi + yj);
            *mid_k.entry(mid).or_insert(0) += 1;
            let deg_map = mid_deg.entry(mid).or_insert(HashMap::new());
            *deg_map.entry(i).or_insert(0) += 1;
            *deg_map.entry(j).or_insert(0) += 1;
        }
    }

    let mut G = 0i64;
    for (&mid, &k) in &mid_k {
        if k < 2 {
            continue;
        }
        let total_pairs = k * (k - 1) / 2;
        let mut adjacent_pairs = 0;
        if let Some(deg_map) = mid_deg.get(&mid) {
            for &d in deg_map.values() {
                adjacent_pairs += d * (d - 1) / 2;
            }
        }
        G += total_pairs - adjacent_pairs;
    }

    T - G
}
