    let n = points.len();
    let mut count = 0;

    for a in 0..n {
        for b in a + 1..n {
            for c in b + 1..n {
                for d in c + 1..n {
                    let p1 = &points[a];
                    let p2 = &points[b];
                    let p3 = &points[c];
                    let p4 = &points[d];
                    let points = [p1, p2, p3, p4];
                    let mut slopes = Vec::new();

                    for i in 0..4 {
                        for j in i + 1..4 {
                            let dx = points[j][0] - points[i][0];
                            let dy = points[j][1] - points[i][1];
                            // Avoid division by using cross multiplication for slope comparison
                            // Represent slope as (dy, dx) reduced to simplest form
                            let g = gcd(dy, dx);
                            let s = if g != 0 {
                                (dy / g, dx / g)
                            } else {
                                (dy, dx)
                            };
                            slopes.push(s);
                        }
                    }

                    // Check for at least one pair of parallel sides (same slope)
                    let mut found = false;
                    for i in 0..slopes.len() {
                        for j in i + 1..slopes.len() {
                            if slopes[i] == slopes[j] {
                                found = true;
                                break;
                            }
                        }
                        if found {
                            break;
                        }
                    }

                    if found {
                        count += 1;
                    }
                }
            }
        }
    }

    count
}

